arguments.new_str:
using Microsoft.ML;
using Microsoft.Extensions.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);

// --- Train the model at startup ---
var mlContext = new MLContext(seed: 42);
var dataPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "customers.csv");

// Load CSV (Churned is "Yes"/"No" text)
var rawData = mlContext.Data.LoadFromTextFile<CustomerDataRaw>(
    dataPath, hasHeader: true, separatorChar: ',');

// Map "Yes"/"No" → true/false boolean Label column
var labelMapping = mlContext.Transforms.Conversion.MapValue(
    "Label",
    new[] { new KeyValuePair<string, bool>("Yes", true), new KeyValuePair<string, bool>("No", false) },
    "Churned");

var labeledData = labelMapping.Fit(rawData).Transform(rawData);

// Build the training pipeline
var pipeline = mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", "Region")
    .Append(mlContext.Transforms.Concatenate("Features", "Age", "Income", "RegionEncoded", "PurchaseHistory"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.FastTree());

// Use cross-validation for small datasets to get reliable metrics
var cvResults = mlContext.BinaryClassification.CrossValidate(labeledData, pipeline, numberOfFolds: 3);
var avgAuc = cvResults.Average(r => r.Metrics.AreaUnderRocCurve);
var avgAcc = cvResults.Average(r => r.Metrics.Accuracy);
var avgF1 = cvResults.Average(r => r.Metrics.F1Score);
Console.WriteLine($"Cross-validation — AUC: {avgAuc:F4}, Accuracy: {avgAcc:F4}, F1: {avgF1:F4}");

// Train final model on full dataset
var model = pipeline.Fit(labeledData);

// Save model for PredictionEnginePool
var modelPath = Path.Combine(builder.Environment.ContentRootPath, "Data", "churn-model.zip");
mlContext.Model.Save(model, labeledData.Schema, modelPath);

// Register pooled prediction engine (thread-safe)
builder.Services.AddPredictionEnginePool<CustomerData, ChurnPrediction>()
    .FromFile(modelPath);

var app = builder.Build();

app.MapGet("/", () => "Churn Predictor API — POST /predict with { age, income, region, purchaseHistory }");

app.MapPost("/predict", (PredictionEnginePool<CustomerData, ChurnPrediction> pool, CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = pool.Predict(input);

    return Results.Ok(new
    {
        churned = prediction.Churned,
        probability = prediction.Probability
    });
});

app.Run();

public sealed record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

